import{_ as t,o as a,c as i,ag as n}from"./chunks/framework.Cmi8ck-J.js";const h=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quick-start.md","filePath":"guide/quick-start.md"}'),r={name:"guide/quick-start.md"};function l(o,e,s,c,p,u){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Get up and running with Link2Pay in under 5 minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you begin, ensure you have:</p><ul><li>✅ A web browser (Chrome, Firefox, or Brave recommended)</li><li>✅ Internet connection</li><li>✅ 5 minutes of time</li></ul><p>That&#39;s it! No credit card, no registration, no complex setup.</p><h2 id="step-1-install-freighter-wallet" tabindex="-1">Step 1: Install Freighter Wallet <a class="header-anchor" href="#step-1-install-freighter-wallet" aria-label="Permalink to &quot;Step 1: Install Freighter Wallet&quot;">​</a></h2><p>Freighter is a Stellar wallet browser extension (similar to MetaMask for Ethereum).</p><ol><li><p><strong>Install the extension:</strong></p><ul><li><a href="https://chrome.google.com/webstore/detail/freighter/bcacfldlkkdogcmkkibnjlakofdplcbk" target="_blank" rel="noreferrer">Chrome/Brave</a></li><li><a href="https://addons.mozilla.org/en-US/firefox/addon/freighter/" target="_blank" rel="noreferrer">Firefox</a></li></ul></li><li><p><strong>Create a new wallet:</strong></p><ul><li>Click the Freighter icon in your browser</li><li>Select &quot;Create new wallet&quot;</li><li><strong>IMPORTANT</strong>: Write down your 24-word recovery phrase</li><li>Store it safely (this cannot be recovered if lost)</li></ul></li><li><p><strong>Switch to Testnet (for testing):</strong></p><ul><li>Open Freighter</li><li>Click settings (gear icon)</li><li>Select &quot;Testnet&quot; from network dropdown</li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">Testnet vs Mainnet</p><p><strong>Testnet</strong>: Free test tokens for development and testing <strong>Mainnet</strong>: Real transactions with real value</p><p>Start on Testnet to experiment safely!</p></div><h2 id="step-2-fund-your-testnet-account" tabindex="-1">Step 2: Fund Your Testnet Account <a class="header-anchor" href="#step-2-fund-your-testnet-account" aria-label="Permalink to &quot;Step 2: Fund Your Testnet Account&quot;">​</a></h2><p>You need XLM to activate your account and pay network fees (&lt; $0.01 per transaction).</p><p><strong>Get free testnet XLM:</strong></p><ol><li>Visit <a href="https://laboratory.stellar.org/#account-creator?network=test" target="_blank" rel="noreferrer">Stellar Laboratory - Friendbot</a></li><li>Paste your Freighter wallet address</li><li>Click &quot;Get test network lumens&quot;</li><li>Wait ~5 seconds for confirmation</li></ol><p>You now have 10,000 testnet XLM to experiment with!</p><div class="warning custom-block"><p class="custom-block-title">Mainnet Activation</p><p>On mainnet, you need to receive at least 1 XLM from another account to activate yours. Exchanges like Coinbase or Kraken can send you XLM.</p></div><h2 id="step-3-access-link2pay" tabindex="-1">Step 3: Access Link2Pay <a class="header-anchor" href="#step-3-access-link2pay" aria-label="Permalink to &quot;Step 3: Access Link2Pay&quot;">​</a></h2><p>Open the application:</p><p><strong>Testnet:</strong> <a href="https://app.link2pay.dev" target="_blank" rel="noreferrer">https://app.link2pay.dev</a></p><div class="tip custom-block"><p class="custom-block-title">No Account Needed</p><p>Link2Pay uses your Stellar wallet address as your identity. No email, no password, no registration forms!</p></div><h2 id="step-4-connect-your-wallet" tabindex="-1">Step 4: Connect Your Wallet <a class="header-anchor" href="#step-4-connect-your-wallet" aria-label="Permalink to &quot;Step 4: Connect Your Wallet&quot;">​</a></h2><ol><li>Click <strong>&quot;Connect Wallet&quot;</strong> in the top right</li><li>Freighter popup will appear</li><li>Click <strong>&quot;Approve&quot;</strong> to connect</li><li>Your wallet address will appear in the navbar</li></ol><p><strong>Authentication:</strong></p><ul><li>First connection requires signing a message (proves you own the wallet)</li><li>No password needed - your private key stays in Freighter</li><li>Sessions last 30 minutes</li></ul><h2 id="step-5-create-your-first-invoice" tabindex="-1">Step 5: Create Your First Invoice <a class="header-anchor" href="#step-5-create-your-first-invoice" aria-label="Permalink to &quot;Step 5: Create Your First Invoice&quot;">​</a></h2><ol><li><p><strong>Navigate to Dashboard:</strong></p><ul><li>Click &quot;Dashboard&quot; in the sidebar</li><li>Click &quot;Create Invoice&quot; button</li></ul></li><li><p><strong>Fill in Invoice Details:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client Name: Acme Corporation</span></span>
<span class="line"><span>Client Email: billing@acme.com</span></span>
<span class="line"><span>Invoice Number: INV-001 (auto-generated if blank)</span></span>
<span class="line"><span>Due Date: 2024-12-31</span></span>
<span class="line"><span>Currency: USDC</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></li><li><p><strong>Add Line Items:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Description: Website Development</span></span>
<span class="line"><span>Quantity: 40</span></span>
<span class="line"><span>Rate: 50</span></span>
<span class="line"><span>Amount: $2,000 (calculated automatically)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p><strong>Optional Fields:</strong></p><ul><li>Tax Rate: 10%</li><li>Discount: $100</li><li>Notes: &quot;Payment due upon completion&quot;</li></ul></li><li><p><strong>Click &quot;Create Invoice&quot;</strong></p></li></ol><p>Your invoice is now in <code>DRAFT</code> status!</p><h2 id="step-6-send-the-invoice" tabindex="-1">Step 6: Send the Invoice <a class="header-anchor" href="#step-6-send-the-invoice" aria-label="Permalink to &quot;Step 6: Send the Invoice&quot;">​</a></h2><ol><li><p><strong>Review your invoice:</strong></p><ul><li>Check all details are correct</li><li>Preview the PDF</li></ul></li><li><p><strong>Mark as sent:</strong></p><ul><li>Click &quot;Send Invoice&quot; button</li><li>Status changes to <code>PENDING</code></li><li>Payment link is now active</li></ul></li><li><p><strong>Share payment link:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://app.link2pay.dev/pay/clx7k8q9a0001...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Copy this link and send it to your client via:</p><ul><li>Email</li><li>Slack</li><li>WhatsApp</li><li>Any messaging platform</li></ul></li></ol><h2 id="step-7-make-a-test-payment" tabindex="-1">Step 7: Make a Test Payment <a class="header-anchor" href="#step-7-make-a-test-payment" aria-label="Permalink to &quot;Step 7: Make a Test Payment&quot;">​</a></h2><p>Let&#39;s simulate a client payment:</p><ol><li><strong>Open the payment link</strong> (in a new incognito window to simulate client)</li><li><strong>Review invoice details</strong> (client view)</li><li><strong>Click &quot;Pay with Freighter&quot;</strong></li><li><strong>Freighter popup appears</strong> with transaction details: <ul><li>Destination: Your wallet address</li><li>Amount: Invoice total in selected currency</li><li>Memo: Invoice number (for matching)</li></ul></li><li><strong>Click &quot;Approve&quot;</strong> to sign and submit</li><li><strong>Wait 3-5 seconds</strong> for blockchain confirmation</li></ol><h2 id="step-8-see-instant-confirmation" tabindex="-1">Step 8: See Instant Confirmation <a class="header-anchor" href="#step-8-see-instant-confirmation" aria-label="Permalink to &quot;Step 8: See Instant Confirmation&quot;">​</a></h2><p>Return to your dashboard:</p><ol><li><strong>Invoice status</strong> automatically updates to <code>PAID</code></li><li><strong>Transaction hash</strong> appears in invoice details</li><li><strong>Audit log</strong> shows payment confirmation</li><li><strong>Funds</strong> are in your wallet immediately</li></ol><p><strong>Verify on blockchain:</strong></p><ul><li>Click transaction hash</li><li>Opens Stellar Expert (blockchain explorer)</li><li>See complete transaction details</li></ul><div class="tip custom-block"><p class="custom-block-title">Real-Time Updates</p><p>The dashboard updates automatically via polling. No page refresh needed!</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Congratulations! You&#39;ve completed the full Link2Pay flow. 🎉</p><h3 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h3><ul><li><strong><a href="/docs-link2pay/guide/concepts.html">Core Concepts</a></strong> - Understand invoice lifecycle, payment matching, etc.</li><li><strong><a href="/docs-link2pay/guide/features/payment-links.html">Features</a></strong> - Explore all Link2Pay capabilities</li><li><strong><a href="/docs-link2pay/guide/integration/frontend.html">API Integration</a></strong> - Integrate into your app</li><li><strong><a href="/docs-link2pay/guide/advanced/security.html">Security Model</a></strong> - How Link2Pay keeps you safe</li></ul><h3 id="try-advanced-features" tabindex="-1">Try Advanced Features <a class="header-anchor" href="#try-advanced-features" aria-label="Permalink to &quot;Try Advanced Features&quot;">​</a></h3><ul><li><strong>Multi-Asset Support</strong>: Create invoices in XLM, USDC, or EURC</li><li><strong>Saved Clients</strong>: Build a client book for faster invoicing</li><li><strong>Bulk Operations</strong>: Create multiple invoices at once</li><li><strong>Webhook Events</strong>: Get notified when invoices are paid</li><li><strong>API Access</strong>: Build custom integrations</li></ul><h3 id="move-to-mainnet" tabindex="-1">Move to Mainnet <a class="header-anchor" href="#move-to-mainnet" aria-label="Permalink to &quot;Move to Mainnet&quot;">​</a></h3><p>When you&#39;re ready for real transactions:</p><ol><li>Switch Freighter to <strong>Mainnet</strong></li><li>Fund your account with real XLM (buy from exchange)</li><li>Connect to Link2Pay (same URL, auto-detects network)</li><li>Create production invoices</li></ol><div class="danger custom-block"><p class="custom-block-title">Security Reminder</p><p>On mainnet, your funds are real. Always:</p><ul><li>Back up your recovery phrase securely</li><li>Never share your private key</li><li>Verify transaction details before signing</li><li>Use hardware wallets for large amounts</li></ul></div><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><p>Stuck? We&#39;re here to help:</p><ul><li>📚 <a href="/docs-link2pay/guide/introduction.html">Full Documentation</a></li><li>💬 <a href="#">Discord Community</a></li><li>🐛 <a href="https://github.com/Link2Pay/link2pay-app/issues" target="_blank" rel="noreferrer">Report Bug</a></li><li>📧 <a href="mailto:support@link2pay.dev" target="_blank" rel="noreferrer">Email Support</a></li></ul><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><p><strong>Common Tasks:</strong></p><table tabindex="0"><thead><tr><th>Task</th><th>Navigation</th></tr></thead><tbody><tr><td>Create invoice</td><td>Dashboard → Create Invoice</td></tr><tr><td>View invoices</td><td>Dashboard → Invoice List</td></tr><tr><td>Check payment status</td><td>Dashboard → Click invoice</td></tr><tr><td>Download PDF</td><td>Invoice Detail → Download PDF</td></tr><tr><td>View transaction</td><td>Invoice Detail → Transaction Hash</td></tr><tr><td>Switch network</td><td>Navbar → Network Toggle</td></tr><tr><td>Disconnect wallet</td><td>Navbar → Wallet Address → Disconnect</td></tr></tbody></table><p><strong>Keyboard Shortcuts:</strong></p><ul><li><code>Ctrl/Cmd + K</code>: Search</li><li><code>Ctrl/Cmd + /</code>: Toggle sidebar</li><li><code>Escape</code>: Close modals</li></ul><p><strong>Testnet Resources:</strong></p><ul><li>Friendbot: <a href="https://laboratory.stellar.org/#account-creator?network=test" target="_blank" rel="noreferrer">https://laboratory.stellar.org/#account-creator?network=test</a></li><li>Horizon API: <a href="https://horizon-testnet.stellar.org" target="_blank" rel="noreferrer">https://horizon-testnet.stellar.org</a></li><li>Stellar Expert: <a href="https://stellar.expert/explorer/testnet" target="_blank" rel="noreferrer">https://stellar.expert/explorer/testnet</a></li></ul><p>Happy invoicing! 🚀</p>`,59)])])}const g=t(r,[["render",l]]);export{h as __pageData,g as default};
